'use client';

import dynamic from 'next/dynamic';
import AdminLayout from '@/components/AdminLayout';
import { useState, useEffect, useRef } from 'react';
import Link from 'next/link';

// Dynamically import Quill to avoid SSR issues
const ReactQuill = dynamic(() => import('react-quill-new'), {
    ssr: false,
    loading: () => <div className="loading-overlay"><div className="spinner" /> Loading editor...</div>,
});

// Load Quill CSS on client only
if (typeof window !== 'undefined') {
    import('react-quill-new/dist/quill.snow.css');
}

const quillModules = {
    toolbar: {
        container: [
            [{ header: [1, 2, 3, false] }],
            [{ font: [] }],
            ['bold', 'italic', 'underline', 'strike'],
            [{ color: [] }, { background: [] }],
            [{ align: [] }],
            [{ list: 'ordered' }, { list: 'bullet' }],
            ['blockquote'],
            ['link', 'image'],
            ['clean'],
        ],
    },
    clipboard: { matchVisual: false },
};

const quillFormats = [
    'header', 'font', 'bold', 'italic', 'underline', 'strike',
    'color', 'background', 'align', 'list', 'blockquote',
    'link', 'image',
];

export default function NewDevotionalPage() {
    const [title, setTitle] = useState('');
    const [author, setAuthor] = useState('');
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
    const [body, setBody] = useState('');
    const [thumbnailPreview, setThumbnailPreview] = useState<string | null>(null);
    const [saving, setSaving] = useState(false);
    const [activeTab, setActiveTab] = useState<'write' | 'preview'>('write');
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleThumbnailClick = () => {
        fileInputRef.current?.click();
    };

    const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setThumbnailPreview(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const stripHtml = (html: string) => {
        return html.replace(/<[^>]*>/g, '').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').trim();
    };

    const handleSave = async (status: 'draft' | 'scheduled') => {
        setSaving(true);
        try {
            // Will connect to Firestore
            const devotional = {
                title,
                body,
                plainText: stripHtml(body),
                date,
                author,
                status,
                thumbnailUrl: thumbnailPreview || '',
            };
            console.log('Saving devotional:', devotional);
            // TODO: await createDevotional(devotional);
            alert(`Devotional ${status === 'draft' ? 'saved as draft' : 'scheduled'}! (Firebase not connected yet)`);
        } catch {
            alert('Error saving devotional');
        } finally {
            setSaving(false);
        }
    };

    const wordCount = stripHtml(body).split(/\s+/).filter(Boolean).length;
    const readingTime = Math.max(1, Math.ceil(wordCount / 200));
    const audioEstimate = Math.max(1, Math.ceil(wordCount / 150));

    return (
        <AdminLayout>
            <div className="page-header">
                <div className="page-header-top">
                    <div>
                        <h1 className="page-title">New Devotional</h1>
                        <p className="page-subtitle">Create and format your daily devotional</p>
                    </div>
                    <div style={{ display: 'flex', gap: 10 }}>
                        <Link href="/devotionals" className="btn btn-ghost">← Back</Link>
                        <button
                            className="btn btn-secondary"
                            onClick={() => handleSave('draft')}
                            disabled={saving}
                        >
                            {saving ? <span className="spinner" /> : '💾'} Save Draft
                        </button>
                        <button
                            className="btn btn-primary"
                            onClick={() => handleSave('scheduled')}
                            disabled={saving || !title || !body}
                        >
                            {saving ? <span className="spinner" /> : '📅'} Schedule
                        </button>
                    </div>
                </div>
            </div>

            <div className="page-body">
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 320px', gap: 24 }}>
                    {/* Left: Editor */}
                    <div>
                        {/* Title */}
                        <div className="form-group">
                            <input
                                className="form-input"
                                type="text"
                                placeholder="Devotional Title..."
                                value={title}
                                onChange={(e) => setTitle(e.target.value)}
                                style={{ fontSize: 20, fontWeight: 700, padding: '14px 16px', letterSpacing: '-0.02em' }}
                            />
                        </div>

                        {/* Editor Tabs */}
                        <div className="tabs" style={{ marginBottom: 0 }}>
                            <button
                                className={`tab${activeTab === 'write' ? ' active' : ''}`}
                                onClick={() => setActiveTab('write')}
                            >
                                ✏️ Write
                            </button>
                            <button
                                className={`tab${activeTab === 'preview' ? ' active' : ''}`}
                                onClick={() => setActiveTab('preview')}
                            >
                                👁️ Preview
                            </button>
                        </div>

                        {/* Rich Text Editor */}
                        {activeTab === 'write' ? (
                            <div className="editor-container" style={{ marginTop: 2 }}>
                                <ReactQuill
                                    theme="snow"
                                    value={body}
                                    onChange={setBody}
                                    modules={quillModules}
                                    formats={quillFormats}
                                    placeholder="Begin writing your devotional...

You can format text, add scripture quotes using blockquotes, embed images, and more. Use the toolbar above to style your content."
                                />
                            </div>
                        ) : (
                            <div className="card" style={{ marginTop: 2, minHeight: 400 }}>
                                <div style={{ fontSize: 12, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 8 }}>
                                    {date && new Date(date + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                                </div>
                                <h2 style={{ fontSize: 24, fontWeight: 700, marginBottom: 4 }}>{title || 'Untitled'}</h2>
                                <div style={{ fontSize: 13, color: 'var(--text-tertiary)', marginBottom: 20 }}>
                                    {author && `By ${author}`}
                                </div>
                                <div
                                    style={{ fontSize: 15, lineHeight: 1.8, color: 'var(--text-secondary)' }}
                                    dangerouslySetInnerHTML={{ __html: body || '<p style="color: var(--text-muted)">No content yet...</p>' }}
                                />
                            </div>
                        )}
                    </div>

                    {/* Right: Metadata Sidebar */}
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                        {/* Publish Details */}
                        <div className="card">
                            <div className="card-title" style={{ marginBottom: 16 }}>📅 Publish Details</div>
                            <div className="form-group">
                                <label className="form-label">Date</label>
                                <input
                                    className="form-input"
                                    type="date"
                                    value={date}
                                    onChange={(e) => setDate(e.target.value)}
                                />
                            </div>
                            <div className="form-group" style={{ marginBottom: 0 }}>
                                <label className="form-label">Author</label>
                                <input
                                    className="form-input"
                                    type="text"
                                    placeholder="Author name"
                                    value={author}
                                    onChange={(e) => setAuthor(e.target.value)}
                                />
                            </div>
                        </div>

                        {/* Thumbnail */}
                        <div className="card">
                            <div className="card-title" style={{ marginBottom: 16 }}>🖼️ Cover Image</div>
                            <input
                                ref={fileInputRef}
                                type="file"
                                accept="image/*"
                                onChange={handleThumbnailChange}
                                style={{ display: 'none' }}
                            />
                            {thumbnailPreview ? (
                                <div>
                                    <img src={thumbnailPreview} alt="Thumbnail" className="image-preview" />
                                    <button
                                        className="btn btn-ghost btn-sm"
                                        style={{ marginTop: 8, width: '100%' }}
                                        onClick={handleThumbnailClick}
                                    >
                                        🔄 Change Image
                                    </button>
                                </div>
                            ) : (
                                <div className="image-upload" onClick={handleThumbnailClick}>
                                    <div className="image-upload-icon">📷</div>
                                    <div className="image-upload-text">Click to upload cover image</div>
                                </div>
                            )}
                        </div>

                        {/* Content Stats */}
                        <div className="card">
                            <div className="card-title" style={{ marginBottom: 16 }}>📊 Content Stats</div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                                <StatRow label="Words" value={wordCount.toString()} />
                                <StatRow label="Reading Time" value={`~${readingTime} min`} />
                                <StatRow label="Audio Estimate" value={`~${audioEstimate} min`} />
                                <StatRow label="Characters" value={stripHtml(body).length.toString()} />
                            </div>
                        </div>

                        {/* Distribution Channels */}
                        <div className="card">
                            <div className="card-title" style={{ marginBottom: 16 }}>📡 Distribution</div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
                                <ChannelToggle icon="📧" label="Email (Mailchimp)" defaultChecked />
                                <ChannelToggle icon="💬" label="WhatsApp" defaultChecked />
                                <ChannelToggle icon="📰" label="Blog (Wix)" defaultChecked />
                                <ChannelToggle icon="🎧" label="Audio (TTS)" defaultChecked />
                            </div>
                        </div>

                        {/* Template Actions */}
                        <div className="card">
                            <div className="card-title" style={{ marginBottom: 16 }}>📋 Templates</div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                                <button className="btn btn-secondary btn-sm" style={{ width: '100%' }}>
                                    📥 Load Template
                                </button>
                                <button
                                    className="btn btn-secondary btn-sm"
                                    style={{ width: '100%' }}
                                    onClick={() => {
                                        if (title && body) {
                                            alert('Template saved! (Firebase not connected yet)');
                                        }
                                    }}
                                >
                                    💾 Save as Template
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </AdminLayout>
    );
}

function StatRow({ label, value }: { label: string; value: string }) {
    return (
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13 }}>
            <span style={{ color: 'var(--text-tertiary)' }}>{label}</span>
            <span style={{ fontWeight: 600, fontVariantNumeric: 'tabular-nums' }}>{value}</span>
        </div>
    );
}

function ChannelToggle({ icon, label, defaultChecked = false }: { icon: string; label: string; defaultChecked?: boolean }) {
    const [checked, setChecked] = useState(defaultChecked);
    return (
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, fontSize: 13 }}>
                <span>{icon}</span>
                <span style={{ color: checked ? 'var(--text-primary)' : 'var(--text-tertiary)' }}>{label}</span>
            </div>
            <label className="toggle">
                <input type="checkbox" checked={checked} onChange={() => setChecked(!checked)} />
                <span className="toggle-slider" />
            </label>
        </div>
    );
}
